sql:
SELECT sales.property_id, sales.sale_price, users.user_id, users.user_name 
FROM sales 
JOIN users ON sales.user_id = users.user_id;

SELECT property_id
FROM properties
WHERE neighborhood_id IN (
  SELECT neighborhood_id
  FROM neighborhoods
  WHERE avg_property_tax > (
    SELECT AVG(avg_property_tax)
    FROM neighborhoods
  )
);

SELECT property_id
FROM properties
WHERE square_footage = (
  SELECT MAX(square_footage)
  FROM properties
);

SELECT AVG(sale_price) AS avg_sale_price
FROM sales
WHERE buyer_id = 1;

SELECT "avg_crime_rate"
FROM "neighborhoods"
WHERE "neighborhood_id" = 'desired_neighborhood_id';

SELECT ACOSH(
    (SELECT AVG(avg_crime_rate) FROM neighborhoods) 
    - 
    (SELECT avg_crime_rate FROM neighborhoods WHERE neighborhood_name = 'Uptown')
) AS deviation_acosh;

